const ROUTES = ["home","about","vision","impact","programmes","robotics","sports",
  "donate","volunteer","partners","policies","testimonials","contact","login","portal","dashboard"];

function t(k){ return (I18N[LANG] && I18N[LANG][k]) || I18N.en[k] || k; }

