/* ---------- reusable components ---------- */
function card(bg,ic,h,p,route){return `<div class="card"><div class="ic ${bg}">${ic}</div><h3>${h}</h3><p>${p}</p>${route?`<a class="more" onclick="go('${route}')">Learn more →</a>`:''}</div>`;}
function prog(img,tag,h,p,route){return `<div class="prog-card" ${route?`onclick="go('${route}')" style="cursor:pointer"`:''}><div class="ph"><span class="tag">${tag}</span><img src="${img}" alt="${h}"></div><div class="body"><h3>${h}</h3><p>${p}</p></div></div>`;}
function quote(bg,init,name,role,text){return `<div class="quote"><div class="qm">"</div><p>${text}</p><div class="who"><div class="av ${bg}">${init}</div><div><b>${name}</b><span>${role}</span></div></div></div>`;}
function team(img,name,role,p){return `<div class="team-card"><div class="ph"><img src="${img}" alt="${name}"></div><h3>${name}</h3><div class="role">${role}</div><p>${p}</p></div>`;}
function tl(yr,h,p){return `<div class="tl-item"><span class="dot"></span><div class="yr">${yr}</div><h3>${h}</h3><p>${p}</p></div>`;}
function eventRow(d,m,h,p,btn){return `<div class="event"><div class="date"><b>${d}</b><span>${m}</span></div><div class="info"><h3>${h}</h3><p>${p}</p></div>${btn?`<a class="btn btn-primary btn-sm" onclick="go('programmes')">${btn} →</a>`:''}</div>`;}
function campaign(img,h,p,pct,raised,goal){return `<div class="campaign"><div class="ph"><img src="${img}" alt="${h}"></div><div class="body"><h3 style="font-size:1.15rem;margin-bottom:10px">${h}</h3><div class="progress"><i style="width:0" data-pct="${pct}"></i></div><div style="display:flex;justify-content:space-between;font-size:.84rem;font-weight:700"><span style="color:var(--green)">${raised}</span><span style="color:var(--muted)">of ${goal}</span></div><p style="color:var(--muted);font-size:.88rem;margin:10px 0 14px">${p}</p><a class="btn btn-navy btn-sm" style="width:100%;justify-content:center" onclick="go('donate')">Donate →</a></div></div>`;}
function course(img,lvl,h,lessons,time,pct){return `<div class="course"><div class="ph"><img src="${img}" alt="${h}"><div class="play"><span>▶</span></div></div><div class="body"><div class="lvl">${lvl}</div><h3>${h}</h3><div class="meta"><span>📚 ${lessons}</span><span>⏱️ ${time}</span></div><div class="progress" style="height:8px"><i style="width:0" data-pct="${pct}"></i></div><a class="btn ${pct==100?'btn-outline':'btn-primary'} btn-sm mt" style="width:100%;justify-content:center" onclick="go('portal')">${pct==100?'Review ✓':pct>0?'Continue':'Start course'} →</a></div></div>`;}
function pageHero(h,p,crumb){return `<section class="page-hero"><div class="wrap"><div class="crumb">${crumb}</div><h1>${h}</h1><p>${p}</p></div></section>`;}
function ctaBand(){return `<section class="block" style="padding-top:0"><div class="wrap"><div class="cta-band"><h2>Be part of the change</h2><p>Donate, volunteer, or partner with us — every contribution helps a young person aspire.</p><div style="display:flex;gap:14px;justify-content:center;flex-wrap:wrap;position:relative"><a class="btn btn-white" onclick="go('donate')">Donate</a><a class="btn btn-ghost" onclick="go('volunteer')">Volunteer</a></div></div></div></section>`;}
function kpis(arr){return `<div class="kpi-grid">${arr.map(([b,s,u])=>`<div class="kpi"><b>${b}</b><span>${s}</span>${u?`<div class="up">${u}</div>`:''}</div>`).join('')}</div>`;}
function table(heads,rows){
  return `<table class="dash-table"><thead><tr>${heads.map(h=>`<th>${h}</th>`).join('')}</tr></thead><tbody>${rows.map(r=>`<tr>${r.map(c=>{
    if(c.includes(':')){const[col,txt]=c.split(':');return `<td><span class="pill pill-${col}">${txt}</span></td>`;}
    return `<td>${c}</td>`;}).join('')}</tr>`).join('')}</tbody></table>`;
}
function dashShell(name,init,role,nav,main){
  return `<div class="dash"><div class="dash-side"><div class="who"><div class="av">${init}</div><div><b>${name}</b><span>${role}</span></div></div><nav class="dash-nav">${nav.map(([n,ic,a])=>`<a class="${a?'active':''}">${ic} ${n}</a>`).join('')}<a onclick="go('home')" style="margin-top:14px">← Sign out</a></nav></div><div class="dash-main">${main}</div></div>`;
}

/* ---------- ROUTER ---------- */
const PAGES = {home:pageHome,about:pageAbout,vision:pageVision,impact:pageImpact,programmes:pageProgrammes,
  robotics:pageRobotics,sports:pageSports,donate:pageDonate,volunteer:pageVolunteer,partners:pagePartners,
  policies:pagePolicies,testimonials:pageTestimonials,contact:pageContact,login:pageLogin,portal:pagePortal,dashboard:pageDashboard};

let CURRENT="home";
function render(){
  const fn = PAGES[CURRENT] || pageHome;
  document.getElementById('app').innerHTML = header() + `<main><div class="page active">${fn()}</div></main>` + footer() + fab();
  // mark active nav
  document.querySelectorAll('.nav-links a[data-r]').forEach(a=>{
    a.classList.toggle('active', a.getAttribute('data-r')===CURRENT);
  });
  try{window.scrollTo(0,0);}catch(e){}
  initAnimations();
}
function go(route){
  if(!ROUTES.includes(route)) route='home';
  CURRENT=route;
  location.hash=route;
  render();
}
window.go=go;

/* ---------- ANIMATIONS (count-up, progress, reveal) ---------- */
function initAnimations(){
  // animated counters
  const obs=new IntersectionObserver((entries)=>{
    entries.forEach(e=>{
      if(e.isIntersecting){
        const el=e.target;
        if(el.dataset.count && !el.dataset.done){
          el.dataset.done=1;
          const end=+el.dataset.count;const dur=1400;const t0=performance.now();
          const fmt=n=>n.toLocaleString('en-GB');
          (function step(now){
            const p=Math.min((now-t0)/dur,1);
            const ease=1-Math.pow(1-p,3);
            el.textContent=fmt(Math.floor(ease*end))+(end>=96&&end<=100?'':'');
            if(p<1)requestAnimationFrame(step);else el.textContent=fmt(end);
          })(t0);
        }
        if(el.dataset.pct && !el.dataset.done){el.dataset.done=1;setTimeout(()=>{el.style.width=el.dataset.pct+'%';},120);}
        obs.unobserve(el);
      }
    });
  },{threshold:.4});
  document.querySelectorAll('[data-count],[data-pct]').forEach(el=>obs.observe(el));
}

/* ---------- INTERACTIONS ---------- */
function showMsg(id){const m=document.getElementById(id);if(m){m.classList.add('show');m.scrollIntoView({behavior:'smooth',block:'center'});}}
window.showMsg=showMsg;
function subscribe(){const e=document.getElementById('newsEmail');if(e&&e.value){document.getElementById('newsMsg').classList.add('show');e.value='';}}
window.subscribe=subscribe;
function toggleLang(){
  LANG = LANG==="en"?"ar":"en";
  document.documentElement.lang = LANG;
  document.documentElement.dir = LANG==="ar"?"rtl":"ltr";
  render();
}
window.toggleLang=toggleLang;

// donation widget
let donFreq='once', donAmt=25;
function refreshDon(){const s=document.getElementById('donAmt');if(s)s.textContent='£'+donAmt+(donFreq==='monthly'?'/mo':'');}
function selAmt(btn,a){document.querySelectorAll('#amtGrid .amt').forEach(x=>x.classList.remove('sel'));btn.classList.add('sel');donAmt=a;const c=document.getElementById('customAmt');if(c)c.value='';refreshDon();}
window.selAmt=selAmt;
function selAmtVal(a){donAmt=a;refreshDon();go('donate');}
window.selAmtVal=selAmtVal;
function clearAmt(){document.querySelectorAll('#amtGrid .amt').forEach(x=>x.classList.remove('sel'));const c=document.getElementById('customAmt');if(c&&c.value)donAmt=+c.value;refreshDon();}
window.clearAmt=clearAmt;
function setFreq(f){donFreq=f;const o=document.getElementById('onceBtn'),m=document.getElementById('monBtn');if(o&&m){o.classList.toggle('sel',f==='once');m.classList.toggle('sel',f==='monthly');}refreshDon();}
window.setFreq=setFreq;

// auth tabs
function authTab(which){
  document.getElementById('loginTab').classList.toggle('active',which==='login');
  document.getElementById('signupTab').classList.toggle('active',which==='signup');
  document.getElementById('signupExtra').style.display = which==='signup'?'block':'none';
}
window.authTab=authTab;

// dashboard tabs
function dashTab(btn,id){
  document.querySelectorAll('.tabs .tab').forEach(t=>t.classList.remove('active'));
  btn.classList.add('active');
  document.querySelectorAll('.tabpane').forEach(p=>p.classList.remove('active'));
  document.getElementById(id).classList.add('active');
}
window.dashTab=dashTab;

// quiz
function quizAns(btn,correct){
  document.querySelectorAll('#quiz .amt').forEach(b=>b.style.opacity=.5);
  btn.style.opacity=1;
  if(correct){btn.classList.add('sel');document.getElementById('quizMsg').classList.add('show');}
  else{btn.style.borderColor='var(--red)';btn.style.color='var(--red)';}
}
window.quizAns=quizAns;

/* ---------- BOOT ---------- */
function boot(){
  const h=location.hash.replace('#','');
  CURRENT = ROUTES.includes(h)?h:'home';
  render();
}
window.addEventListener('hashchange',()=>{
  const h=location.hash.replace('#','');
  if(ROUTES.includes(h)&&h!==CURRENT){CURRENT=h;render();}
});
boot();
